var soc2 = Number(global.get("SocBat2")[0]);
var mode1 = Number(global.get("statusBat2")[0]) ;
var min = Number(global.get("setMin"));
var max = Number(global.get("setMax"));

// Instelbare marge (Hysteresis) van 2%
var margin = 0 ; 

if (mode1 === 3 && soc2 <= min) {
    msg.payload = 0; 
    node.status({ fill: "yellow", shape: "dot", text: "reached min (" + soc2 + "%): 0" })
}

else if (mode1 === 2 && soc2 >= max) {
    msg.payload = 0; 
    node.status({ fill: "yellow", shape: "dot", text: "reached max (" + soc2 + "%): 0" })
}

// 3. START/KEEP GOING: Alleen als we ruim boven de min + marge zitten
// Dit voorkomt dat hij direct weer aangaat zodra hij 1% oplaadt
else if (soc2 > (min + margin) && soc2 < (max - margin)) {
    msg.payload = 1;
    node.status({ fill: "green", shape: "dot", text: "Soc in range (" + soc2 + "%): 1" })
}

// 4. NEUTRALE ZONE: Zit tussen de stop-grens en de herstart-marge in
else {
    // We sturen geen nieuwe payload (of payload 0) om de huidige status te behouden
    msg.payload = 0; 
    node.status({ fill: "grey", shape: "ring", text: "standby: " + soc2 + "%" });
}


return msg;

