    msg.payload = 1;
    node.status({ fill: "green", shape: "dot", text: "Sunny (" + solpwr + "W): 1" });
}
else { // goto manual in case no good charge condition
    msg.payload = 0;
    node.status({ fill: "yellow", shape: "dot", text: "Not enough Sun (" + solpwr + "W): 0" });
}

return msg;

